import React, { useState } from 'react';
import JSZip from 'jszip';
import './App.css';

// Dynamically require the logo file directly from src
const logoImg = require('./WhatsApp Image 2026-07-20 at 9.49.24 PM.jpeg');

function App() {
  const [zipImages, setZipImages] = useState([]);
  const [isProcessingZip, setIsProcessingZip] = useState(false);

  // Extract images from user uploaded .zip file
  const handleZipUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setIsProcessingZip(true);
    setZipImages([]);

    try {
      const zip = new JSZip();
      const zipContent = await zip.loadAsync(file);
      const imagePromises = [];

      zipContent.forEach((relativePath, zipEntry) => {
        if (!zipEntry.dir && /\.(png|jpe?g|svg|webp|gif)$/i.test(zipEntry.name)) {
          const promise = zipEntry.async('blob').then((blob) => ({
            name: zipEntry.name,
            url: URL.createObjectURL(blob),
          }));
          imagePromises.push(promise);
        }
      });

      const extractedImages = await Promise.all(imagePromises);
      setZipImages(extractedImages);
    } catch (err) {
      alert('Error reading ZIP file. Please upload a valid .zip archive.');
    } finally {
      setIsProcessingZip(false);
    }
  };

  return (
    <div className="app-container" style={{ minHeight: '100vh', padding: '40px 20px', background: '#0a0a0a' }}>
      <div style={{ maxWidth: '1000px', margin: '0 auto', textAlign: 'center' }}>
        
        {/* BRAND LOGO */}
        <div style={{ marginBottom: '30px' }}>
          <img 
            src={logoImg} 
            alt="Jillu Curtains" 
            style={{ width: '220px', height: 'auto', display: 'block', margin: '0 auto 15px' }} 
          />
        </div>

        {/* ZIP ARCHIVE EXTRACTOR SECTION */}
        <div className="card" style={{ padding: '30px', background: '#141414', border: '1px solid #d4af37', borderRadius: '12px' }}>
          <h2 className="gold-text" style={{ marginBottom: '10px' }}>Jillu Curtains Catalog ZIP Extractor</h2>
          <p style={{ color: '#aaa', marginBottom: '25px' }}>
            Upload your <code>.zip</code> archive to extract and view your custom curtain portfolio.
          </p>

          <input 
            type="file" 
            accept=".zip" 
            onChange={handleZipUpload} 
            style={{ color: '#fff', margin: '0 auto', display: 'block', cursor: 'pointer' }} 
          />

          {isProcessingZip && (
            <p style={{ color: '#d4af37', marginTop: '20px', fontWeight: 'bold' }}>
              Unpacking ZIP archive...
            </p>
          )}
        </div>

        {/* EXTRACTED GALLERY DISPLAY */}
        {zipImages.length > 0 && (
          <div style={{ marginTop: '40px', textAlign: 'left' }}>
            <h3 className="gold-text" style={{ marginBottom: '20px', fontSize: '1.5rem', textAlign: 'center' }}>
              Extracted Catalog Images ({zipImages.length})
            </h3>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '20px' }}>
              {zipImages.map((img, idx) => (
                <div 
                  key={idx} 
                  style={{ 
                    background: '#1a1a1a', 
                    border: '1px solid #333', 
                    borderRadius: '8px', 
                    overflow: 'hidden', 
                    padding: '10px' 
                  }}
                >
                  <img 
                    src={img.url} 
                    alt={img.name} 
                    style={{ width: '100%', height: '220px', objectFit: 'cover', borderRadius: '6px' }} 
                  />
                  <p style={{ color: '#888', fontSize: '0.8rem', marginTop: '10px', wordBreak: 'break-all', textAlign: 'center' }}>
                    {img.name}
                  </p>
                </div>
              ))}
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

export default App;
